# checkers/game.py

from .board import Board
from .player import Player

class Game:
    def __init__(self):
        self.board = Board()
        self.player1 = Player("black")
        self.player2 = Player("white")
        self.current_player = self.player1

    def switch_turn(self):
        if self.current_player == self.player1:
            self.current_player = self.player2
        else:
            self.current_player = self.player1

    def get_move_input(self):
        # Logic to get move input from the user in notation (e.g., 'a1-b2')
        return input(f"{self.current_player.color.capitalize()} player's move: ").strip().lower()

    def handle_move(self, move):
        moves = move.split('-')
        if len(moves) != 2:
            print("Invalid move format. Use from-to notation (e.g., 'a1-b2')")
            return False
        from_pos = self._convert_position(moves[0])
        to_pos = self._convert_position(moves[1])
        if not self.board.is_valid_move(from_pos, to_pos):
            print("Invalid move")
            return False
        self.board.move_piece(from_pos, to_pos)
        self.current_player.make_move((from_pos, to_pos), self.board)
        return True

    def _convert_position(self, pos):
        # Convert position notation (e.g., 'a1') to board indices
        column = ord(pos[0]) - 97
        row = int(pos[1]) - 1
        return (row, column)

```

